import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';
import Sidebar from '../components/common/Sidebar';
import {
  DashboardDataTable,
  DashboardHeader,
  DashboardKpiCard,
  DashboardKpiGrid,
  DashboardSection,
} from '../components/common/DashboardShell';
import { useGlobalFilters } from '../context/GlobalFilterContext';
import { buildDashboardQuery } from '../utils/dashboardFilters';
import { StatusBadge, PriorityBadge, formatDate } from '../utils/statusHelpers';

const dash = (value) => value || '-';

export default function PlanningBoardPage() {
  const navigate = useNavigate();
  const { filters } = useGlobalFilters();
  const query = useMemo(() => buildDashboardQuery(filters), [filters]);
  const [data, setData] = useState({ kpis: {}, requests: [] });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const loadPlanning = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const res = await api.get(`/planning${query ? `?${query}` : ''}`);
      setData({
        kpis: res.data?.kpis || {},
        requests: res.data?.requests || [],
      });
    } catch (err) {
      setError(err.response?.data?.error || 'Unable to load planning data');
    } finally {
      setLoading(false);
    }
  }, [query]);

  useEffect(() => { loadPlanning(); }, [loadPlanning]);

  const rows = data.requests || [];
  const kpis = data.kpis || {};

  return (
    <div className="page">
      <Sidebar />
      <div className="main-content">
        <DashboardHeader
          title="Production Planning"
          description="Plan approved work, assigned jobs, printers, and technicians using the global application filters."
          dashboard="planning"
          actions={<button className="btn btn-secondary btn-sm" onClick={loadPlanning} disabled={loading}>{loading ? 'Refreshing...' : 'Refresh'}</button>}
        />

        <div className="page-body">
          {error && <div className="alert alert-error" style={{ marginBottom: '1rem' }}>{error}</div>}

          <DashboardKpiGrid>
            <DashboardKpiCard label="Planned Requests" value={kpis.plannedRequests ?? 0} helper="Planned or assigned work" tone="info" />
            <DashboardKpiCard label="Active Jobs" value={kpis.activeJobs ?? 0} helper="Assigned or in progress" tone="good" />
            <DashboardKpiCard label="Printer Utilization" value={`${kpis.printerUtilization ?? 0}%`} helper="Active printers with jobs" tone="warning" />
            <DashboardKpiCard label="Technician Utilization" value={`${kpis.technicianUtilization ?? 0}%`} helper="Active technicians with jobs" tone="neutral" />
          </DashboardKpiGrid>

          {loading ? (
            <div className="card" style={{ textAlign: 'center', padding: '3rem' }}>
              <span className="spinner" style={{ width: 32, height: 32 }} />
            </div>
          ) : (
            <DashboardSection
              title="Planning Table"
              description="Requests currently approved, prioritized, planned, assigned, or in progress."
            >
              <DashboardDataTable
                title="Production Planning Requests"
                rows={rows}
                filename="production-planning.csv"
                pageSize={12}
                columns={[
                  { label: 'Request ID', key: 'request_number' },
                  { label: 'Title', key: 'title' },
                  { label: 'Printer', key: row => dash(row.printer_name) },
                  { label: 'Technician', key: row => dash(row.technician_name) },
                  { label: 'Planned Start', key: 'planned_start_date', render: row => formatDate(row.planned_start_date) || '-' },
                  { label: 'Planned End', key: 'planned_end_date', render: row => formatDate(row.planned_end_date) || '-' },
                  { label: 'Priority', key: 'priority', render: row => <PriorityBadge priority={row.priority} /> },
                  { label: 'Status', key: 'status', render: row => <StatusBadge status={row.status} /> },
                ]}
                onRowClick={row => navigate(`/requests/${row.id}`)}
              />
            </DashboardSection>
          )}
        </div>
      </div>
    </div>
  );
}
